import React from 'react';
import { Box, Button, CircularProgress, Stack } from '@mui/material';
import EventBusyIcon from '@mui/icons-material/EventBusy';
import { useNavigate } from '@tanstack/react-router';
import { EventServices, EventServicesError } from '@/api';
import { useInfiniteScroll } from '@/hooks/useInfiniteScroll';
import { InfiniteScrollList } from '@/components/InfiniteScrollList';
import { EmptyState } from '@/components/ui/EmptyState';
import { EventCard } from './EventCard';
import { EventResult } from '@/types/event.types';
import { CallStatus } from '@/types/api.types';
import { Pathname } from '@/constants/Routes';

export const EventsList: React.FC = () => {
    const navigate = useNavigate();
    
    const {
        items: events,
        loading,
        hasMore,
        loadMore,
        error,
        refresh
    } = useInfiniteScroll<EventResult>({
        fetchFunction: EventServices.GetUpcomingEvents,
        initialPageSize: 10,
        autoLoad: true
    });

    const handleEventEdit = (eventId: string) => {
        navigate({ to: `${Pathname.Events_Edit}/${eventId}` as string });
    };

    const renderEventCard = (event: EventResult, index: number) => {
        return (
            <EventCard 
                key={`${event.id}-${index}`} 
                event={event}
                onEventEdit={handleEventEdit}
                defaultCollapsed
            />
        );
    };

    // Determine the status for StatusMessage
    const getStatus = (): CallStatus => {
        if (loading && events.length === 0) return CallStatus.InProgress;
        if (error) return CallStatus.Failure;
        if (!loading && events.length === 0) return CallStatus.Success;
        return CallStatus.Success;
    };

    const status = getStatus();

    // Initial loading
    if (status === CallStatus.InProgress) {
        return (
            <Stack spacing={2}>
                <Box sx={{ display: 'flex', justifyContent: 'center', py: 6 }} role="status" aria-live="polite">
                    <CircularProgress aria-label="Loading events" />
                </Box>
            </Stack>
        );
    }

    // Error
    if (status === CallStatus.Failure) {
        return (
            <Stack spacing={2}>
                <EmptyState
                    variant="error"
                    helper={error || EventServicesError.GetEventsError(0)}
                    action={
                        <Button color="inherit" size="small" onClick={refresh}>
                            Retry
                        </Button>
                    }
                />
            </Stack>
        );
    }

    // Empty success
    if (events.length === 0) {
        return (
            <Stack spacing={2}>
                <EmptyState
                    variant="hint"
                    illustration={<EventBusyIcon sx={{ fontSize: 48 }} />}
                    heading="No upcoming events"
                    helper="Check back soon — new events are posted regularly."
                />
            </Stack>
        );
    }

    return (
        <Stack spacing={2}>
            <InfiniteScrollList
                items={events}
                renderItem={renderEventCard}
                loading={loading}
                hasMore={hasMore}
                loadMore={loadMore}
                error={error}
                onRetry={refresh}
                emptyMessage="No upcoming events found."
            />
        </Stack>
    );
};